## Product Search Endpoint with Typesense

### 1. Install the Typesense client

```bash
npm install typesense
# or
pip install typesense
```

---

### 2. Configure the client

```typescript
// lib/typesenseClient.ts
import Typesense from 'typesense';

export const client = new Typesense.Client({
  nodes: [{ host: process.env.TYPESENSE_HOST, port: 443, protocol: 'https' }],
  apiKey: process.env.TYPESENSE_API_KEY,
  connectionTimeoutSeconds: 5,
});
```

---

### 3. Define the product schema (if not already created)

```typescript
// scripts/createProductCollection.ts
await client.collections().create({
  name: 'products',
  fields: [
    { name: 'id',          type: 'string' },
    { name: 'name',        type: 'string' },
    { name: 'description', type: 'string' },
    { name: 'price',       type: 'float' },
    { name: 'category',    type: 'string', facet: true },
    { name: 'location',    type: 'geopoint' },  // for your geo-spatial filters
  ],
  default_sorting_field: 'price',
});
```

---

### 4. Wire the search endpoint

```typescript
// routes/productSearch.ts
import { Router, Request, Response } from 'express';
import { client } from '../lib/typesenseClient';

const router = Router();

router.get('/api/products/search', async (req: Request, res: Response) => {
  const {
    q = '*',
    category,
    lat,
    lng,
    radius_km = '10',
    page = '1',
    per_page = '20',
  } = req.query as Record<string, string>;

  const searchParams: Record<string, unknown> = {
    q,
    query_by: 'name,description',   // typo-tolerance applies automatically
    page: parseInt(page),
    per_page: parseInt(per_page),
  };

  // Optional category filter
  if (category) {
    searchParams.filter_by = `category:=${category}`;
  }

  // Geo-spatial filter — leverages Typesense's built-in geo support
  if (lat && lng) {
    const geoFilter = `location:(${lat}, ${lng}, ${radius_km} km)`;
    searchParams.filter_by = searchParams.filter_by
      ? `${searchParams.filter_by} && ${geoFilter}`
      : geoFilter;
  }

  try {
    const results = await client
      .collections('products')
      .documents()
      .search(searchParams);

    res.json({
      hits:  results.hits?.map(h => h.document) ?? [],
      total: results.found,
      page:  results.page,
    });
  } catch (err) {
    console.error('Typesense search error:', err);
    res.status(500).json({ error: 'Search failed' });
  }
});

export default router;
```

---

### Key things wired in

| Feature | How it's handled |
|---|---|
| **Typo tolerance** | Automatic via `query_by` — no extra config needed |
| **Geo-spatial filtering** | `location:(lat, lng, radius km)` filter |
| **Faceting** | `category` field marked `facet: true` for drill-downs |
| **Pagination** | `page` + `per_page` params |

---

### Environment variables needed

```env
TYPESENSE_HOST=your-typesense-host.example.com
TYPESENSE_API_KEY=your-search-only-api-key
```

Use a **search-only API key** (scoped read-only) for the endpoint — never expose your admin key.

